// src/vite-plugin.js
var fs = require("fs");
var path = require("path");
var QUICK_DEV_SW;
var swPaths = [
  path.join(__dirname, "quick-dev-sw.js"),
  // dist/ or src/ when flat
  path.join(__dirname, "../quick-dev-sw.js")
  // unlikely but possible
];
for (const swPath of swPaths) {
  if (fs.existsSync(swPath)) {
    QUICK_DEV_SW = fs.readFileSync(swPath, "utf8");
    break;
  }
}
if (!QUICK_DEV_SW) {
  throw new Error("Could not find quick-dev-sw.js");
}
function quickLocal(options = {}) {
  return {
    name: "quick-local",
    configureServer(server) {
      server.middlewares.use((req, res, next) => {
        const url = req.url?.split("?")[0];
        if (url === "/quick-dev-sw.js") {
          res.setHeader("Content-Type", "application/javascript");
          res.setHeader("Cache-Control", "no-cache");
          res.end(QUICK_DEV_SW);
          return;
        }
        if (url === "/client/quick.js") {
          res.writeHead(307, {
            "Location": "https://quick.shopify.io/client/quick-local.js",
            "Cache-Control": "no-cache"
          });
          res.end();
          return;
        }
        next();
      });
    }
  };
}
module.exports = { quickLocal };
